  const undo=()=>{if(!g.playing||g.winLine||!g.moves.length)return;clearTimeout(g.timer);const count=g.mode==='ai'?Math.min(2,g.moves.length):1;for(let n=0;n<count;n++){const m=g.moves.pop();g.board[m.i]=0}g.lastMove=g.moves.at(-1)?.i??-1;g.turn=g.mode==='ai'?1:(g.moves.at(-1)?.p===1?2:1);g.anim=null;g.particles=[];setStatus(`${g.turn===1?'黑棋':'白棋'} · 落子`)};
  g.action=(a,on)=>{if(a==='undo'&&on)undo()};
  const point=e=>{const b=canvas.getBoundingClientRect(),x=(e.clientX-b.left)*720/b.width,y=(e.clientY-b.top)*720/b.height,c=Math.round((x-margin)/gap),r=Math.round((y-margin)/gap);return inside(r,c)&&Math.hypot(x-(margin+c*gap),y-(margin+r*gap))<gap*.48?r*size+c:-1};
  canvas.onpointermove=e=>{if(!g.playing)return;g.hover=point(e)};canvas.onpointerleave=()=>g.hover=-1;canvas.onpointerdown=e=>{e.preventDefault();if(!g.playing||g.winLine||g.mode==='ai'&&g.turn===2)return;const i=point(e);if(i>=0&&!g.board[i])place(i,g.turn)};
  const stone=(x,y,p,r=20,alpha=1)=>{ctx.save();ctx.globalAlpha=alpha;ctx.shadowColor=p===1?'#000':'#fff';ctx.shadowBlur=8;const grad=ctx.createRadialGradient(x-7,y-8,2,x,y,r);if(p===1){grad.addColorStop(0,'#686868');grad.addColorStop(.22,'#262626');grad.addColorStop(.72,'#070707');grad.addColorStop(1,'#000')}else{grad.addColorStop(0,'#fff');grad.addColorStop(.35,'#f4f1e9');grad.addColorStop(.78,'#cbc6bb');grad.addColorStop(1,'#8e887d')}ctx.fillStyle=grad;ctx.beginPath();ctx.arc(x,y,r,0,7);ctx.fill();ctx.strokeStyle=p===1?'#000':'#a69f91';ctx.lineWidth=1.3;ctx.stroke();ctx.restore()};
