  g.draw=()=>{if(!g.playing)return;ctx.drawImage(g.texture,0,0);const inner=28,frame=12;ctx.save();ctx.strokeStyle='#4c2414';ctx.lineWidth=frame;ctx.strokeRect(inner,inner,664,664);ctx.strokeStyle='#f1ca71';ctx.lineWidth=2;ctx.strokeRect(inner+8,inner+8,648,648);ctx.restore();ctx.strokeStyle='rgba(24,18,11,.78)';ctx.lineWidth=1.35;for(let n=0;n<size;n++){ctx.beginPath();ctx.moveTo(margin,margin+n*gap);ctx.lineTo(margin+14*gap,margin+n*gap);ctx.stroke();ctx.beginPath();ctx.moveTo(margin+n*gap,margin);ctx.lineTo(margin+n*gap,margin+14*gap);ctx.stroke()}ctx.fillStyle='#24170e';for(const [r,c] of [[3,3],[3,7],[3,11],[7,3],[7,7],[7,11],[11,3],[11,7],[11,11]]){ctx.beginPath();ctx.arc(margin+c*gap,margin+r*gap,4.4,0,7);ctx.fill()}if(g.hover>=0&&!g.board[g.hover]&&!g.winLine){const [r,c]=rc(g.hover);stone(margin+c*gap,margin+r*gap,g.turn,19,.28)}for(let i=0;i<225;i++)if(g.board[i]){const [r,c]=rc(i),scale=g.anim?.i===i?Math.min(1,1+(1-Math.min(1,g.anim.t/.34))*Math.sin(Math.min(1,g.anim.t/.34)*Math.PI)*.3):1;stone(margin+c*gap,margin+r*gap,g.board[i],20*scale)}if(g.lastMove>=0){const [r,c]=rc(g.lastMove);ctx.strokeStyle='#ef4444';ctx.lineWidth=2.2;ctx.beginPath();ctx.arc(margin+c*gap,margin+r*gap,6,0,7);ctx.stroke()}for(const p of g.particles){ctx.globalAlpha=1-p.t/p.life;ctx.fillStyle=p.color;ctx.beginPath();ctx.arc(p.x,p.y,1.5+(1-p.t/p.life)*2,0,7);ctx.fill()}ctx.globalAlpha=1;if(g.anim){const [r,c]=rc(g.anim.i),pulse=24+g.anim.t*55;ctx.strokeStyle=`rgba(255,211,112,${Math.max(0,1-g.anim.t/.42)})`;ctx.lineWidth=3;ctx.beginPath();ctx.arc(margin+c*gap,margin+r*gap,pulse,0,7);ctx.stroke()}if(g.winLine){const [a,b]=g.winLine.map(rc),pulse=16+Math.sin(performance.now()/130)*5;ctx.save();ctx.strokeStyle='#ffdf78';ctx.lineWidth=7;ctx.shadowColor='#ffb300';ctx.shadowBlur=pulse;ctx.beginPath();ctx.moveTo(margin+a[1]*gap,margin+a[0]*gap);ctx.lineTo(margin+b[1]*gap,margin+b[0]*gap);ctx.stroke();ctx.restore()}};
  g.destroy=()=>clearTimeout(g.timer);setup();return g;
