  dom.innerHTML=`<div class="mode-panel"><h3>${L('⚔️ 火柴人格斗 · 雷霆对决','⚔️ Stick Fighter · Thunder Duel')}</h3><p>${L('先选择真人双人或 AI 对手；选择 AI 时还可决定挑战强度，确认后再进入擂台。','Choose local PVP or an AI opponent. AI mode also lets you select the challenge level before entering the arena.')}</p><div class="setup-grid"><label class="setup-field">${L('对战模式','Battle mode')}<select id="stickSetupMode"><option value="ai">${L('对战 AI','Vs AI')}</option><option value="pvp">${L('本地真人双人','Local PVP')}</option></select></label><label class="setup-field" id="stickSetupDifficultyField">${L('AI 难度','AI difficulty')}<select id="stickSetupDifficulty"><option value="easy">${L('简单','Easy')}</option><option value="normal">${L('普通','Normal')}</option><option value="hard">${L('困难','Hard')}</option></select></label></div><button class="setup-start" id="stickSetupStart">${L('开始对战','Start Battle')}</button></div>`;
  const mode=$('#stickSetupMode'),difficulty=$('#stickSetupDifficulty'),field=$('#stickSetupDifficultyField');
